contracts/HiringEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title TrustFolioHiringEscrow
 * @notice Escrow-based hiring agreements between employers and TrustFolio-verified talent.
 *
 * @dev State machine per request:
 *
 *   Pending ──► Accepted ──► Completed ──► Released
 *      │                         │
 *      ├──► Declined (refund)    └──► Disputed ──► (admin resolves)
 *      └──► Cancelled (refund)                ├──► Released (to talent)
 *                                             └──► Cancelled (refund employer)
 *
 *   Auto-release: 7 days after talent marks completion, anyone can trigger auto-release.
 *   Platform fee: 2.5% of escrow amount deducted on successful release.
 */
contract TrustFolioHiringEscrow is Ownable, ReentrancyGuard {

    // ── Constants ─────────────────────────────────────────────────────────────

    uint256 public constant AUTO_RELEASE_DELAY  = 7 days;
    uint256 public constant PLATFORM_FEE_BPS    = 250;   // 2.5%
    uint256 public constant BPS                 = 10_000;

    // ── Types ─────────────────────────────────────────────────────────────────

    enum Status {
        Pending,    // 0 – request created, awaiting talent response
        Accepted,   // 1 – talent accepted, work in progress
        Completed,  // 2 – talent confirmed completion, awaiting employer release or auto-release
        Released,   // 3 – payment released to talent
        Disputed,   // 4 – dispute raised, awaiting admin resolution
        Cancelled,  // 5 – cancelled (refund to employer)
        Declined    // 6 – talent declined (refund to employer)
    }

    struct HiringRequest {
        uint256 requestId;
        address employer;
        address talent;
        uint256 amount;            // escrow amount in wei
        string  title;
        string  description;
        uint256 deadline;          // Unix timestamp (informational)
        uint256 createdAt;
        uint256 acceptedAt;
        uint256 completedAt;
        Status  status;
        bool    talentConfirmed;   // talent marked job done
        bool    employerReleased;  // employer explicitly released payment
    }

    // ── Storage ───────────────────────────────────────────────────────────────

    uint256 private _nextRequestId = 1;

    mapping(uint256 => HiringRequest) public requests;
    mapping(address => uint256[])     private _employerRequests;
    mapping(address => uint256[])     private _talentRequests;

    address public treasury;

    uint256 public totalEscrowVolume;  // cumulative amount deposited
    uint256 public totalFeesCollected;
    uint256 public totalRequestsCount;

    // ── Events ────────────────────────────────────────────────────────────────

    event RequestCreated(
        uint256 indexed requestId,
        address indexed employer,
        address indexed talent,
        uint256 amount,
        string  title
    );
    event RequestAccepted(uint256 indexed requestId, address talent);
    event RequestDeclined(uint256 indexed requestId, address talent);
    event CompletionConfirmed(uint256 indexed requestId, address confirmedBy);
    event PaymentReleased(uint256 indexed requestId, address indexed talent, uint256 amount, uint256 fee);
    event DisputeRaised(uint256 indexed requestId, address indexed raisedBy);
    event DisputeResolved(uint256 indexed requestId, bool releasedToTalent);
    event RequestCancelled(uint256 indexed requestId, address indexed by);
    event TreasuryUpdated(address indexed newTreasury);

    // ── Errors ────────────────────────────────────────────────────────────────

    error RequestNotFound(uint256 requestId);
    error InvalidStatus(uint256 requestId, Status current);
    error NotAuthorized();
    error InvalidTalentAddress();
    error DeadlineMustBeFuture();
    error PaymentRequired();
    error TitleRequired();
    error AutoReleaseNotReady(uint256 readyAt);
    error TransferFailed();

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor(address _treasury) Ownable(msg.sender) {
        treasury = _treasury;
    }

    // ── Employer actions ──────────────────────────────────────────────────────

    /**
     * @notice Create a hiring request and deposit escrow payment.
     * @param talent      Wallet address of the talent (INFT owner).
     * @param title       Short title of the job.
     * @param description Full job description.
     * @param deadline    Expected completion timestamp.
     */
    function createRequest(
        address talent,
        string calldata title,
        string calldata description,
        uint256 deadline
    ) external payable nonReentrant returns (uint256) {
        if (msg.value == 0) revert PaymentRequired();
        if (talent == address(0) || talent == msg.sender) revert InvalidTalentAddress();
        if (deadline <= block.timestamp) revert DeadlineMustBeFuture();
        if (bytes(title).length == 0) revert TitleRequired();

        uint256 requestId = _nextRequestId++;

        requests[requestId] = HiringRequest({
            requestId:       requestId,
            employer:        msg.sender,
            talent:          talent,
            amount:          msg.value,
            title:           title,
            description:     description,
            deadline:        deadline,
            createdAt:       block.timestamp,
            acceptedAt:      0,
            completedAt:     0,
            status:          Status.Pending,
            talentConfirmed: false,
            employerReleased: false
        });

        _employerRequests[msg.sender].push(requestId);
        _talentRequests[talent].push(requestId);

        totalEscrowVolume  += msg.value;
        totalRequestsCount++;

        emit RequestCreated(requestId, msg.sender, talent, msg.value, title);
        return requestId;
    }

    /**
     * @notice Employer cancels a pending request (refund, only before acceptance).
     */
    function cancelRequest(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.employer != msg.sender) revert NotAuthorized();
        if (req.status != Status.Pending) revert InvalidStatus(requestId, req.status);

        req.status = Status.Cancelled;
        _send(req.employer, req.amount);

        emit RequestCancelled(requestId, msg.sender);
    }

    /**
     * @notice Employer explicitly releases payment after talent confirms completion.
     */
    function releasePayment(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.employer != msg.sender) revert NotAuthorized();
        if (req.status != Status.Accepted && req.status != Status.Completed)
            revert InvalidStatus(requestId, req.status);

        req.employerReleased = true;
        _releaseToTalent(requestId, req);
    }

    // ── Talent actions ────────────────────────────────────────────────────────

    /**
     * @notice Accept a pending hiring request.
     */
    function acceptRequest(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.talent != msg.sender) revert NotAuthorized();
        if (req.status != Status.Pending) revert InvalidStatus(requestId, req.status);

        req.status     = Status.Accepted;
        req.acceptedAt = block.timestamp;

        emit RequestAccepted(requestId, msg.sender);
    }

    /**
     * @notice Decline a pending hiring request (full refund to employer).
     */
    function declineRequest(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.talent != msg.sender) revert NotAuthorized();
        if (req.status != Status.Pending) revert InvalidStatus(requestId, req.status);

        req.status = Status.Declined;
        _send(req.employer, req.amount);

        emit RequestDeclined(requestId, msg.sender);
    }

    /**
     * @notice Talent marks the job as completed.
     *         Starts the 7-day auto-release window.
     */
    function confirmCompletion(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.talent != msg.sender) revert NotAuthorized();
        if (req.status != Status.Accepted) revert InvalidStatus(requestId, req.status);

        req.talentConfirmed = true;
        req.completedAt     = block.timestamp;
        req.status          = Status.Completed;

        emit CompletionConfirmed(requestId, msg.sender);
    }

    // ── Auto-release ──────────────────────────────────────────────────────────

    /**
     * @notice Anyone can trigger auto-release 7 days after talent confirmed completion.
     *         Protects talent from non-responsive employers.
     */
    function autoRelease(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (req.status != Status.Completed) revert InvalidStatus(requestId, req.status);

        uint256 readyAt = req.completedAt + AUTO_RELEASE_DELAY;
        if (block.timestamp < readyAt)
            revert AutoReleaseNotReady(readyAt);

        _releaseToTalent(requestId, req);
    }

    // ── Dispute ───────────────────────────────────────────────────────────────

    /**
     * @notice Raise a dispute on an accepted or completed request.
     *         Either employer or talent can raise a dispute.
     *         Funds frozen until admin resolves.
     */
    function raiseDispute(uint256 requestId) external nonReentrant {
        HiringRequest storage req = _load(requestId);
        if (msg.sender != req.employer && msg.sender != req.talent) revert NotAuthorized();
        if (req.status != Status.Accepted && req.status != Status.Completed)
            revert InvalidStatus(requestId, req.status);

        req.status = Status.Disputed;
        emit DisputeRaised(requestId, msg.sender);
    }

    /**
     * @notice Admin resolves a dispute: release to talent or refund employer.
     */
    function resolveDispute(uint256 requestId, bool releaseToTalent)
        external
        onlyOwner
        nonReentrant
    {
        HiringRequest storage req = _load(requestId);
        if (req.status != Status.Disputed) revert InvalidStatus(requestId, req.status);

        emit DisputeResolved(requestId, releaseToTalent);

        if (releaseToTalent) {
            _releaseToTalent(requestId, req);
        } else {
            req.status = Status.Cancelled;
            _send(req.employer, req.amount); // full refund, no fee for failed disputes
            emit RequestCancelled(requestId, address(this));
        }
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getRequest(uint256 requestId)
        external
        view
        returns (HiringRequest memory)
    {
        return _load(requestId);
    }

    function getEmployerRequests(address employer)
        external
        view
        returns (uint256[] memory)
    {
        return _employerRequests[employer];
    }

    function getTalentRequests(address talent)
        external
        view
        returns (uint256[] memory)
    {
        return _talentRequests[talent];
    }

    function autoReleaseReadyAt(uint256 requestId)
        external
        view
        returns (uint256)
    {
        HiringRequest storage req = _load(requestId);
        if (req.status != Status.Completed) return 0;
        return req.completedAt + AUTO_RELEASE_DELAY;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setTreasury(address newTreasury) external onlyOwner {
        treasury = newTreasury;
        emit TreasuryUpdated(newTreasury);
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _releaseToTalent(uint256 requestId, HiringRequest storage req) internal {
        req.status = Status.Released;

        uint256 fee       = (req.amount * PLATFORM_FEE_BPS) / BPS;
        uint256 talentAmt = req.amount - fee;

        totalFeesCollected += fee;

        _send(req.talent, talentAmt);
        if (fee > 0) _send(treasury, fee);

        emit PaymentReleased(requestId, req.talent, talentAmt, fee);
    }

    function _send(address to, uint256 amount) internal {
        (bool ok,) = payable(to).call{value: amount}("");
        if (!ok) revert TransferFailed();
    }

    function _load(uint256 requestId)
        internal
        view
        returns (HiringRequest storage)
    {
        HiringRequest storage req = requests[requestId];
        if (req.requestId == 0) revert RequestNotFound(requestId);
        return req;
    }
}

contracts/Marketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title TrustFolioMarketplace
 * @notice Custodial marketplace for buying, selling, and making offers on TrustFolio INFTs.
 * @dev INFTs are transferred to this contract when listed (custodial model).
 *      A 2.5% platform fee is deducted from every sale and forwarded to treasury.
 *
 *      Flow:
 *        Seller: approve INFT → createListing → (wait for buyer)
 *        Buyer:  buyListing (pays price) | makeOffer → seller acceptOffer
 *        Seller: cancelListing (returns INFT)
 *        Buyer:  cancelOffer (refunds offer amount)
 */
contract TrustFolioMarketplace is Ownable, ReentrancyGuard {

    // ── Constants ─────────────────────────────────────────────────────────────

    uint256 public constant FEE_BPS = 250;    // 2.5% platform fee
    uint256 public constant BPS     = 10_000;
    uint256 public constant MAX_OFFER_DURATION = 30 days;

    // ── Storage ───────────────────────────────────────────────────────────────

    uint256 private _nextListingId = 1;
    uint256 private _nextOfferId   = 1;

    IERC721 public immutable inftContract;
    address public treasury;

    struct Listing {
        uint256 listingId;
        uint256 tokenId;
        address seller;
        uint256 price;      // in wei (0G tokens)
        uint256 listedAt;
        bool    active;
    }

    struct Offer {
        uint256 offerId;
        uint256 tokenId;
        address buyer;
        uint256 amount;     // in wei (0G tokens) — held in escrow
        uint256 expiresAt;
        bool    active;
    }

    mapping(uint256 => Listing)   public listings;
    mapping(uint256 => Offer)     public offers;
    mapping(uint256 => uint256)   public tokenToActiveListing; // tokenId → listingId (0 = none)
    mapping(uint256 => uint256[]) public tokenOffers;          // tokenId → offerId[]

    uint256[] private _activeListingIds;

    uint256 public totalVolume;  // cumulative sales volume in wei
    uint256 public totalSales;   // number of completed sales
    uint256 public totalFees;    // cumulative fees collected

    // ── Events ────────────────────────────────────────────────────────────────

    event Listed(
        uint256 indexed listingId,
        uint256 indexed tokenId,
        address indexed seller,
        uint256 price
    );
    event ListingCancelled(uint256 indexed listingId, uint256 indexed tokenId);
    event Sale(
        uint256 indexed listingId,
        uint256 indexed tokenId,
        address seller,
        address indexed buyer,
        uint256 price,
        uint256 fee
    );
    event OfferMade(
        uint256 indexed offerId,
        uint256 indexed tokenId,
        address indexed buyer,
        uint256 amount,
        uint256 expiresAt
    );
    event OfferAccepted(
        uint256 indexed offerId,
        uint256 indexed tokenId,
        address seller,
        address indexed buyer,
        uint256 amount,
        uint256 fee
    );
    event OfferCancelled(uint256 indexed offerId);
    event TreasuryUpdated(address indexed newTreasury);

    // ── Errors ────────────────────────────────────────────────────────────────

    error ListingNotActive(uint256 listingId);
    error NotSeller(address caller, address seller);
    error NotBuyer(address caller, address buyer);
    error InsufficientPayment(uint256 sent, uint256 required);
    error OfferExpired(uint256 offerId);
    error OfferNotActive(uint256 offerId);
    error TokenAlreadyListed(uint256 tokenId, uint256 existingListingId);
    error NotTokenOwner();
    error TransferFailed();
    error InvalidPrice();
    error InvalidDuration();

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor(address _inftContract, address _treasury)
        Ownable(msg.sender)
    {
        inftContract = IERC721(_inftContract);
        treasury     = _treasury;
    }

    // ── Listing ───────────────────────────────────────────────────────────────

    /**
     * @notice List an INFT for sale. Caller must have approved this contract first.
     * @param tokenId Token to list.
     * @param price   Sale price in wei (0G tokens).
     */
    function createListing(uint256 tokenId, uint256 price)
        external
        nonReentrant
        returns (uint256)
    {
        if (price == 0) revert InvalidPrice();
        if (inftContract.ownerOf(tokenId) != msg.sender) revert NotTokenOwner();
        if (tokenToActiveListing[tokenId] != 0)
            revert TokenAlreadyListed(tokenId, tokenToActiveListing[tokenId]);

        // Pull NFT into marketplace escrow
        inftContract.transferFrom(msg.sender, address(this), tokenId);

        uint256 listingId = _nextListingId++;
        listings[listingId] = Listing({
            listingId: listingId,
            tokenId:   tokenId,
            seller:    msg.sender,
            price:     price,
            listedAt:  block.timestamp,
            active:    true
        });

        tokenToActiveListing[tokenId] = listingId;
        _activeListingIds.push(listingId);

        emit Listed(listingId, tokenId, msg.sender, price);
        return listingId;
    }

    /**
     * @notice Cancel a listing. Returns INFT to the seller.
     */
    function cancelListing(uint256 listingId) external nonReentrant {
        Listing storage lst = listings[listingId];
        if (!lst.active) revert ListingNotActive(listingId);
        if (lst.seller != msg.sender && owner() != msg.sender)
            revert NotSeller(msg.sender, lst.seller);

        lst.active = false;
        tokenToActiveListing[lst.tokenId] = 0;
        _removeActiveListingId(listingId);

        inftContract.transferFrom(address(this), lst.seller, lst.tokenId);

        emit ListingCancelled(listingId, lst.tokenId);
    }

    // ── Buying ────────────────────────────────────────────────────────────────

    /**
     * @notice Buy a listed INFT at the asking price.
     *         Excess 0G tokens are refunded.
     */
    function buyListing(uint256 listingId) external payable nonReentrant {
        Listing storage lst = listings[listingId];
        if (!lst.active) revert ListingNotActive(listingId);
        if (msg.value < lst.price) revert InsufficientPayment(msg.value, lst.price);

        lst.active = false;
        tokenToActiveListing[lst.tokenId] = 0;
        _removeActiveListingId(listingId);

        uint256 fee       = (lst.price * FEE_BPS) / BPS;
        uint256 sellerAmt = lst.price - fee;

        totalVolume += lst.price;
        totalFees   += fee;
        totalSales++;

        // Transfer INFT to buyer
        inftContract.transferFrom(address(this), msg.sender, lst.tokenId);

        // Pay seller
        _send(lst.seller, sellerAmt);

        // Platform fee
        if (fee > 0) _send(treasury, fee);

        // Refund overpayment
        if (msg.value > lst.price)
            _send(msg.sender, msg.value - lst.price);

        emit Sale(listingId, lst.tokenId, lst.seller, msg.sender, lst.price, fee);
    }

    // ── Offers ────────────────────────────────────────────────────────────────

    /**
     * @notice Make an offer on any INFT (listed or unlisted).
     *         Offer amount is held in contract escrow until accepted/cancelled/expired.
     * @param tokenId         Target INFT.
     * @param durationSeconds Offer validity window (max 30 days).
     */
    function makeOffer(uint256 tokenId, uint256 durationSeconds)
        external
        payable
        nonReentrant
        returns (uint256)
    {
        if (msg.value == 0) revert InvalidPrice();
        if (durationSeconds == 0 || durationSeconds > MAX_OFFER_DURATION)
            revert InvalidDuration();

        uint256 offerId = _nextOfferId++;
        uint256 expires = block.timestamp + durationSeconds;

        offers[offerId] = Offer({
            offerId:   offerId,
            tokenId:   tokenId,
            buyer:     msg.sender,
            amount:    msg.value,
            expiresAt: expires,
            active:    true
        });
        tokenOffers[tokenId].push(offerId);

        emit OfferMade(offerId, tokenId, msg.sender, msg.value, expires);
        return offerId;
    }

    /**
     * @notice Accept a pending offer. Caller must own the INFT (directly or via listing).
     */
    function acceptOffer(uint256 offerId) external nonReentrant {
        Offer storage ofr = offers[offerId];
        if (!ofr.active) revert OfferNotActive(offerId);
        if (block.timestamp > ofr.expiresAt) revert OfferExpired(offerId);

        ofr.active = false;

        uint256 fee       = (ofr.amount * FEE_BPS) / BPS;
        uint256 sellerAmt = ofr.amount - fee;

        totalVolume += ofr.amount;
        totalFees   += fee;
        totalSales++;

        // Determine if token is held in marketplace escrow
        uint256 listingId = tokenToActiveListing[ofr.tokenId];
        if (listingId != 0 && listings[listingId].seller == msg.sender) {
            // Seller has active listing — close it and transfer from escrow
            listings[listingId].active = false;
            tokenToActiveListing[ofr.tokenId] = 0;
            _removeActiveListingId(listingId);
            inftContract.transferFrom(address(this), ofr.buyer, ofr.tokenId);
        } else {
            // Token is with seller directly
            if (inftContract.ownerOf(ofr.tokenId) != msg.sender) revert NotTokenOwner();
            inftContract.transferFrom(msg.sender, ofr.buyer, ofr.tokenId);
        }

        _send(msg.sender, sellerAmt);
        if (fee > 0) _send(treasury, fee);

        emit OfferAccepted(offerId, ofr.tokenId, msg.sender, ofr.buyer, ofr.amount, fee);
    }

    /**
     * @notice Cancel your own offer and receive a full refund.
     */
    function cancelOffer(uint256 offerId) external nonReentrant {
        Offer storage ofr = offers[offerId];
        if (!ofr.active) revert OfferNotActive(offerId);
        if (ofr.buyer != msg.sender) revert NotBuyer(msg.sender, ofr.buyer);

        ofr.active = false;
        _send(msg.sender, ofr.amount);

        emit OfferCancelled(offerId);
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getActiveListings() external view returns (Listing[] memory) {
        uint256 len = _activeListingIds.length;
        Listing[] memory result = new Listing[](len);
        for (uint256 i; i < len; ++i) {
            result[i] = listings[_activeListingIds[i]];
        }
        return result;
    }

    function getListing(uint256 listingId) external view returns (Listing memory) {
        return listings[listingId];
    }

    function getOffer(uint256 offerId) external view returns (Offer memory) {
        return offers[offerId];
    }

    function getTokenOffers(uint256 tokenId) external view returns (Offer[] memory) {
        uint256[] memory ids = tokenOffers[tokenId];
        Offer[] memory result = new Offer[](ids.length);
        for (uint256 i; i < ids.length; ++i) {
            result[i] = offers[ids[i]];
        }
        return result;
    }

    function activeListingCount() external view returns (uint256) {
        return _activeListingIds.length;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setTreasury(address newTreasury) external onlyOwner {
        treasury = newTreasury;
        emit TreasuryUpdated(newTreasury);
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _send(address to, uint256 amount) internal {
        (bool ok,) = payable(to).call{value: amount}("");
        if (!ok) revert TransferFailed();
    }

    function _removeActiveListingId(uint256 listingId) internal {
        uint256 len = _activeListingIds.length;
        for (uint256 i; i < len; ++i) {
            if (_activeListingIds[i] == listingId) {
                _activeListingIds[i] = _activeListingIds[len - 1];
                _activeListingIds.pop();
                break;
            }
        }
    }
}

contracts/SoulBoundCredential.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title IERC5192 — Minimal Soulbound NFTs
 * @dev https://eips.ethereum.org/EIPS/eip-5192
 */
interface IERC5192 {
    /// @notice Emitted when the locking status is changed to locked.
    event Locked(uint256 tokenId);
    /// @notice Emitted when the locking status is changed to unlocked.
    event Unlocked(uint256 tokenId);
    /// @notice Returns the locking status of an Soulbound Token
    function locked(uint256 tokenId) external view returns (bool);
}

/**
 * @title SoulBoundCredential
 * @notice Non-transferable ERC-721 credential tokens (ERC-5192 compliant).
 *         Deployed on 0G Chain (chainId 16602, evm-version cancun).
 *         Each token represents an AI-verified portfolio credential stored
 *         on 0G decentralized storage with a cryptographic Merkle root hash.
 *
 * Tier system:
 *   Diamond: score 90-100 (neon white)
 *   Gold:    score 75-89  (neon amber)
 *   Silver:  score 50-74  (neon cyan)
 *   Bronze:  score 0-49   (neon purple) — not minted, only displayed
 */
contract SoulBoundCredential is ERC721, IERC5192, Ownable {

    // ── Storage ───────────────────────────────────────────────────────────

    uint256 private _nextTokenId;

    struct Credential {
        address  recipient;
        string   skillCategory;      // "code" | "design" | "writing" | "document" | "other"
        uint256  score;              // 0-100 overall
        uint256  originalityScore;
        uint256  qualityScore;
        uint256  complexityScore;
        uint256  authenticityScore;
        string   proofRootHash;      // 0G Storage hash of the full verification JSON
        string   fileRootHash;       // 0G Storage hash of the portfolio file
        uint256  timestamp;          // block.timestamp at mint
        string   metadataURI;        // on-chain metadata URI (JSON)
    }

    mapping(uint256 => Credential)   public  credentials;
    mapping(address  => uint256[])   private _walletTokens;
    mapping(string   => uint256)     private _fileHashToToken;  // fileRootHash → tokenId (0 = not minted)

    // ── Events ────────────────────────────────────────────────────────────

    event CredentialMinted(
        uint256 indexed tokenId,
        address indexed recipient,
        string          skillCategory,
        uint256         score,
        string          proofRootHash,
        string          fileRootHash
    );

    // ── Errors ────────────────────────────────────────────────────────────

    error SoulBoundNonTransferable();
    error ScoreTooLow(uint256 score, uint256 minimum);
    error AlreadyMinted(string fileRootHash, uint256 existingTokenId);
    error TokenDoesNotExist(uint256 tokenId);

    // ── Constructor ───────────────────────────────────────────────────────

    constructor() ERC721("TrustFolio Credential", "TFCRED") Ownable(msg.sender) {
        _nextTokenId = 1;
    }

    // ── ERC-5192 ──────────────────────────────────────────────────────────

    /// @notice All TrustFolio credentials are permanently locked (soul-bound).
    function locked(uint256 /*tokenId*/) external pure override returns (bool) {
        return true;
    }

    // ── Transfer override (OZ v5 pattern) ─────────────────────────────────

    /**
     * @dev Block all transfers except minting (from == address(0)).
     *      Uses the OZ v5 _update hook.
     */
    function _update(address to, uint256 tokenId, address auth)
        internal
        override
        returns (address)
    {
        address from = _ownerOf(tokenId);
        if (from != address(0)) {
            revert SoulBoundNonTransferable();
        }
        return super._update(to, tokenId, auth);
    }

    // ── Minting ───────────────────────────────────────────────────────────

    /**
     * @notice Mint a soul-bound credential to a recipient.
     * @dev    Only callable by contract owner (TrustFolio server wallet).
     *         Requires score >= 50 (Silver tier or above).
     *         Each fileRootHash can only be minted once.
     */
    function mintCredential(
        address recipient,
        string  memory skillCategory,
        uint256 score,
        uint256 originalityScore,
        uint256 qualityScore,
        uint256 complexityScore,
        uint256 authenticityScore,
        string  memory proofRootHash,
        string  memory fileRootHash,
        string  memory metadataURI
    ) external onlyOwner returns (uint256) {
        if (score < 50) revert ScoreTooLow(score, 50);

        uint256 existing = _fileHashToToken[fileRootHash];
        if (existing != 0) revert AlreadyMinted(fileRootHash, existing);

        uint256 tokenId = _nextTokenId++;

        _safeMint(recipient, tokenId);
        emit Locked(tokenId);

        credentials[tokenId] = Credential({
            recipient:          recipient,
            skillCategory:      skillCategory,
            score:              score,
            originalityScore:   originalityScore,
            qualityScore:       qualityScore,
            complexityScore:    complexityScore,
            authenticityScore:  authenticityScore,
            proofRootHash:      proofRootHash,
            fileRootHash:       fileRootHash,
            timestamp:          block.timestamp,
            metadataURI:        metadataURI
        });

        _walletTokens[recipient].push(tokenId);
        _fileHashToToken[fileRootHash] = tokenId;

        emit CredentialMinted(tokenId, recipient, skillCategory, score, proofRootHash, fileRootHash);

        return tokenId;
    }

    // ── View functions ────────────────────────────────────────────────────

    function getCredential(uint256 tokenId) external view returns (Credential memory) {
        if (tokenId == 0 || tokenId >= _nextTokenId) revert TokenDoesNotExist(tokenId);
        return credentials[tokenId];
    }

    function getWalletTokens(address wallet) external view returns (uint256[] memory) {
        return _walletTokens[wallet];
    }

    function getTokenByFileHash(string memory fileRootHash) external view returns (uint256) {
        return _fileHashToToken[fileRootHash];
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        if (tokenId == 0 || tokenId >= _nextTokenId) revert TokenDoesNotExist(tokenId);
        return credentials[tokenId].metadataURI;
    }

    function totalSupply() external view returns (uint256) {
        return _nextTokenId - 1;
    }

    // ── supportsInterface ─────────────────────────────────────────────────

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721)
        returns (bool)
    {
        // ERC-5192 interface ID: 0xb45a3c0e
        return interfaceId == 0xb45a3c0e || super.supportsInterface(interfaceId);
    }
}

contracts/TrustFolioINFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title TrustFolioINFT
 * @notice ERC-7857 Intelligent NFT — verified professional portfolios on 0G Network
 * @dev Transferable NFT containing AI verification scores, encrypted metadata hash,
 *      and skill badges. Encrypted portfolio metadata is stored on 0G Storage;
 *      only the current owner can decrypt it via their private key.
 *
 *      ERC-7857 Intelligent NFT standard:
 *        - AI-generated metadata embedded on-chain
 *        - Verification proof anchored to 0G Storage
 *        - Score-based tier classification
 *        - Transferable (unlike ERC-5192 soul-bound tokens)
 */
contract TrustFolioINFT is ERC721, Ownable, ReentrancyGuard {

    // ── Storage ───────────────────────────────────────────────────────────────

    uint256 private _nextTokenId = 1;

    uint256 public mintingFee   = 0.001 ether;   // configurable minting fee in 0G
    uint256 public constant MIN_SCORE = 60;        // minimum AI score to mint

    struct INFT {
        address  originalOwner;
        string   skillCategory;          // "code" | "design" | "writing" | "document" | "other"
        uint256  score;                  // 0–100 overall AI score
        uint256  originalityScore;
        uint256  qualityScore;
        uint256  complexityScore;
        uint256  authenticityScore;
        string   encryptedMetadataHash;  // 0G Storage root hash (encrypted with owner pubkey)
        string   proofRootHash;          // 0G Storage root hash of AI verification proof JSON
        string   fileRootHash;           // 0G Storage root hash of original portfolio file
        string[] badges;                 // earned skill badge identifiers
        uint256  mintedAt;
        string   tier;                   // "diamond" | "gold" | "silver"
        string   metadataURI;            // on-chain JSON metadata (base64 data URI)
    }

    mapping(uint256 => INFT)    private _tokens;
    mapping(address => uint256[]) private _walletTokens;
    mapping(string  => uint256) private _fileHashToTokenId;

    address public treasury;

    // ── Events ────────────────────────────────────────────────────────────────

    event INFTMinted(
        uint256 indexed tokenId,
        address indexed owner,
        string  skillCategory,
        uint256 score,
        string  tier
    );
    event MintingFeeUpdated(uint256 oldFee, uint256 newFee);
    event TreasuryUpdated(address oldTreasury, address newTreasury);

    // ── Errors ────────────────────────────────────────────────────────────────

    error ScoreTooLow(uint256 score, uint256 minimum);
    error AlreadyMinted(string fileRootHash, uint256 existingTokenId);
    error TokenDoesNotExist(uint256 tokenId);
    error InsufficientFee(uint256 provided, uint256 required);
    error TransferFailed();

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor(address _treasury)
        ERC721("TrustFolio INFT", "TINFT")
        Ownable(msg.sender)
    {
        treasury = _treasury;
    }

    // ── Minting ───────────────────────────────────────────────────────────────

    /**
     * @notice Mint a verified portfolio as an Intelligent NFT.
     * @dev Only the contract owner (TrustFolio server wallet) can mint, ensuring
     *      the AI score has been verified off-chain before issuance.
     *      The minting fee (in 0G tokens) is forwarded to the treasury.
     */
    function mintINFT(
        address        to,
        string calldata skillCategory,
        uint256        score,
        uint256        originalityScore,
        uint256        qualityScore,
        uint256        complexityScore,
        uint256        authenticityScore,
        string calldata encryptedMetadataHash,
        string calldata proofRootHash,
        string calldata fileRootHash,
        string[] calldata badges,
        string calldata metadataURI
    ) external payable onlyOwner nonReentrant returns (uint256) {

        if (score < MIN_SCORE)
            revert ScoreTooLow(score, MIN_SCORE);

        uint256 existing = _fileHashToTokenId[fileRootHash];
        if (existing != 0)
            revert AlreadyMinted(fileRootHash, existing);

        if (msg.value < mintingFee)
            revert InsufficientFee(msg.value, mintingFee);

        uint256 tokenId = _nextTokenId++;

        string memory tier = _computeTier(score);

        _tokens[tokenId] = INFT({
            originalOwner:         to,
            skillCategory:         skillCategory,
            score:                 score,
            originalityScore:      originalityScore,
            qualityScore:          qualityScore,
            complexityScore:       complexityScore,
            authenticityScore:     authenticityScore,
            encryptedMetadataHash: encryptedMetadataHash,
            proofRootHash:         proofRootHash,
            fileRootHash:          fileRootHash,
            badges:                badges,
            mintedAt:              block.timestamp,
            tier:                  tier,
            metadataURI:           metadataURI
        });

        _walletTokens[to].push(tokenId);
        _fileHashToTokenId[fileRootHash] = tokenId;

        _safeMint(to, tokenId);

        // Forward fee to treasury
        if (msg.value > 0) {
            (bool ok,) = payable(treasury).call{value: msg.value}("");
            if (!ok) revert TransferFailed();
        }

        emit INFTMinted(tokenId, to, skillCategory, score, tier);
        return tokenId;
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getINFT(uint256 tokenId) external view returns (INFT memory) {
        if (_ownerOf(tokenId) == address(0)) revert TokenDoesNotExist(tokenId);
        return _tokens[tokenId];
    }

    function getWalletTokens(address wallet) external view returns (uint256[] memory) {
        return _walletTokens[wallet];
    }

    function getTokenByFileHash(string calldata fileRootHash) external view returns (uint256) {
        return _fileHashToTokenId[fileRootHash];
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        if (_ownerOf(tokenId) == address(0)) revert TokenDoesNotExist(tokenId);
        return _tokens[tokenId].metadataURI;
    }

    function totalSupply() external view returns (uint256) {
        return _nextTokenId - 1;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setMintingFee(uint256 newFee) external onlyOwner {
        emit MintingFeeUpdated(mintingFee, newFee);
        mintingFee = newFee;
    }

    function setTreasury(address newTreasury) external onlyOwner {
        emit TreasuryUpdated(treasury, newTreasury);
        treasury = newTreasury;
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _computeTier(uint256 score) internal pure returns (string memory) {
        if (score >= 90) return "diamond";
        if (score >= 75) return "gold";
        return "silver"; // 60–74
    }
}

